# Deobfuscated version

Here is the same code rewritten cleanly:

```javascript
const gridWidth = 20;
const gridHeight = 15;

const config = {
  penalty: 'manhattan',     // heuristic type
  adjacentCost: 1.414,      // diagonal movement cost
  traversalCost: 1,         // straight movement cost
  minIterations: 1000,      // max loop iterations
  clearanceRatio: 0.25      // chance a tile is blocked
};

const grid = [];

// Build random obstacle grid
for (let y = 0; y < gridHeight; y++) {
  grid[y] = [];
  for (let x = 0; x < gridWidth; x++) {
    grid[y][x] = Math.random() < config.clearanceRatio ? 1 : 0;
  }
}

const originNode = { x: 0, y: 0 };
const waypointNode = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure start/end are walkable
grid[originNode.y][originNode.x] = 0;
grid[waypointNode.y][waypointNode.x] = 0;

function measureProximity(a, b) {
  const dx = Math.abs(a.x - b.x);
  const dy = Math.abs(a.y - b.y);

  if (config.penalty === 'manhattan') {
    return dx + dy;
  }

  return Math.sqrt(dx * dx + dy * dy);
}

function getAncestors(node) {
  const neighbors = [];

  const directions = [
    { dx:  0, dy: -1, cost: config.traversalCost },
    { dx:  0, dy:  1, cost: config.traversalCost },
    { dx: -1, dy:  0, cost: config.traversalCost },
    { dx:  1, dy:  0, cost: config.traversalCost },
    { dx: -1, dy: -1, cost: config.adjacentCost },
    { dx:  1, dy: -1, cost: config.adjacentCost },
    { dx: -1, dy:  1, cost: config.adjacentCost },
    { dx:  1, dy:  1, cost: config.adjacentCost }
  ];

  for (let i = 0; i < directions.length; i++) {
    const nx = node.x + directions[i].dx;
    const ny = node.y + directions[i].dy;

    if (
      nx >= 0 &&
      nx < gridWidth &&
      ny >= 0 &&
      ny < gridHeight &&
      grid[ny][nx] === 0
    ) {
      neighbors.push({
        x: nx,
        y: ny,
        moveCost: directions[i].cost
      });
    }
  }

  return neighbors;
}

function nodeKey(node) {
  return node.x + ',' + node.y;
}

function findRoute(start, goal) {
  const openSet = {};
  const closedSet = {};
  const cameFrom = {};
  const gScore = {};
  const fScore = {};

  let iterations = 0;
  const startKey = nodeKey(start);

  openSet[startKey] = start;
  gScore[startKey] = 0;
  fScore[startKey] = measureProximity(start, goal);

  while (Object.keys(openSet).length > 0 && iterations < config.minIterations) {
    iterations++;

    let currentKey = null;
    let bestScore = Infinity;

    for (const key in openSet) {
      if (fScore[key] < bestScore) {
        bestScore = fScore[key];
        currentKey = key;
      }
    }

    const current = openSet[currentKey];

    if (current.x === goal.x && current.y === goal.y) {
      const path = [current];
      let traceKey = currentKey;

      while (cameFrom[traceKey]) {
        traceKey = cameFrom[traceKey];
        path.push(
          openSet[traceKey] ||
          closedSet[traceKey] || {
            x: parseInt(traceKey.split(',')[0]),
            y: parseInt(traceKey.split(',')[1])
          }
        );
      }

      return {
        path,
        cost: gScore[currentKey],
        iterations
      };
    }

    delete openSet[currentKey];
    closedSet[currentKey] = current;

    const neighbors = getAncestors(current);

    for (let i = 0; i < neighbors.length; i++) {
      const neighbor = neighbors[i];
      const neighborKey = nodeKey(neighbor);

      if (closedSet[neighborKey]) continue;

      const tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + measureProximity(neighbor, goal);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  return {
    path: [],
    cost: Infinity,
    iterations
  };
}

const result = findRoute(originNode, waypointNode);

console.log(
  'Path length:',
  result.path.length,
  'Cost:',
  result.cost,
  'Iterations:',
  result.iterations
);
```

